const body = $json.body || $json;
const headers = $json.headers || {};

const expectedKey = $env.COMFYUI_DYNAMIC_API_KEY;
const providedKey = headers['x-api-key'] || headers['X-API-Key'];

function timingSafeEqual(a, b) {
  if (a.length !== b.length) return false;
  let result = 0;
  for (let i = 0; i < a.length; i++) {
    result |= a.charCodeAt(i) ^ b.charCodeAt(i);
  }
  return result === 0;
}

if (expectedKey && expectedKey.length > 0) {
  if (!providedKey) {
    return [{ json: { error: 'Authentication required', code: 401 } }];
  }
  if (!timingSafeEqual(expectedKey, providedKey)) {
    return [{ json: { error: 'Invalid API key', code: 403 } }];
  }
} else if (providedKey) {
  return [{ json: { error: 'Server not configured for API key auth', code: 401 } }];
}

return [{
  json: {
    prompt: body.prompt || body.message || 'Create a beautiful landscape image',
    channel: body.channel || '#general',
    model: body.model || 'local-model',
    max_tokens: parseInt(body.max_tokens || '2000'),
    temperature: parseFloat(body.temperature || '0.7'),
    top_p: parseFloat(body.top_p || '0.9')
  }
}];

