const body = $json;
const channel = $items('Validate and Auth')[0].json.channel;

const choice = body.choices && body.choices[0] ? body.choices[0] : null;
const message = choice ? choice.message : null;
const content = message ? message.content : '';

let workflowJson = content.trim();

// Handle ```json with optional space
const jsonMatch = workflowJson.match(/```(?:json)?\s*([\s\S]*?)```/);
if (jsonMatch) {
  workflowJson = jsonMatch[1].trim();
}

// Remove any escaped newlines
workflowJson = workflowJson.replace(/\\n/g, '\n');

try {
  const parsed = JSON.parse(workflowJson);
  const workflow = parsed.workflow || parsed;

  return [{
    json: {
      success: true,
      workflow: workflow,
      channel: channel,
      raw_response: content,
      model: body.model || 'unknown',
      timestamp: new Date().toISOString()
    }
  }];
} catch (error) {
  return [{
    json: {
      success: false,
      error: error.message,
      channel: channel,
      raw_response: content,
      timestamp: new Date().toISOString()
    }
  }];
}

const body = $json;
const channel = $items('Process LLM Response')[0].json.channel;
const promptId = body.prompt_id || body.id || 'unknown';
const node_ids = body.node_ids || [];

return [{
  json: {
    success: true,
    prompt_id: promptId,
    nodes_queued: node_ids.length,
    channel: channel,
    timestamp: new Date().toISOString()
  }
}];
